```class Solution {
public:
    vector<int> sequentialDigits(int low, int high) {
        vector<int> res;
        for (int digits = 1; digits <= 9; ++digits) {
            int num = 0;
            for (int i = 0; i < digits; ++i) {
                num = num * 10 + i + 1;
            }
            while (num <= high && num >= low) {
                if (num >= low) res.push_back(num);
                int add = 1;
                for (int i = digits - 1; i >= 0; --i) {
                    num += add;
                    add *= 10;
                }
            }
        }
        sort(res.begin(), res.end());
        return res;
    }
};
